class Solution:
    def minimumIncrements(self, nums, target):
        import itertools
        m = len(target)
        full = (1 << m) - 1
        from math import gcd
        def lcm_set(idxs):
            l = 1
            for i in idxs:
                l = l * target[i] // gcd(l, target[i])
            return l
        best = None
        n = len(nums)
        for choice in itertools.product(range(1 << m), repeat=n):
            mask = 0
            cost = 0
            for i, s in enumerate(choice):
                if s == 0:
                    continue
                idxs = [j for j in range(m) if s & (1 << j)]
                L = lcm_set(idxs)
                num = nums[i]
                cost += (-num) % L
                mask |= s
            if mask == full:
                if best is None or cost < best:
                    best = cost
        return best if best is not None else 0

