from math import gcd
class Solution:
    def minimumIncrements(self, nums, target):
        m = len(target)
        full = (1 << m) - 1
        lcm_of = [1] * (1 << m)
        for mask in range(1, 1 << m):
            l = 1
            for j in range(m):
                if mask & (1 << j):
                    l = l * target[j] // gcd(l, target[j])
            lcm_of[mask] = l
        INF = float('inf')
        dp = [INF] * (1 << m)
        dp[0] = 0
        for num in nums:
            ndp = dp[:]
            for mask in range(1 << m):
                if dp[mask] == INF:
                    continue
                base = dp[mask]
                for s in range(1, 1 << m):
                    L = lcm_of[s]
                    cost = (-num) % L
                    nm = mask | s
                    val = base + cost
                    if val < ndp[nm]:
                        ndp[nm] = val
            dp = ndp
        return dp[full]

