var minimumIncrements = function(nums, target) {
    function gcd(a, b) { while (b) { [a, b] = [b, a % b]; } return a; }
    const m = target.length;
    const full = (1 << m) - 1;
    const lcmOf = new Array(1 << m).fill(1);
    for (let mask = 1; mask < (1 << m); mask++) {
        let l = 1;
        for (let j = 0; j < m; j++) {
            if (mask & (1 << j)) l = l / gcd(l, target[j]) * target[j];
        }
        lcmOf[mask] = l;
    }
    const INF = Infinity;
    let dp = new Array(1 << m).fill(INF);
    dp[0] = 0;
    for (const num of nums) {
        const ndp = dp.slice();
        for (let mask = 0; mask < (1 << m); mask++) {
            if (dp[mask] === INF) continue;
            const base = dp[mask];
            for (let s = 1; s < (1 << m); s++) {
                const L = lcmOf[s];
                const cost = ((-num) % L + L) % L;
                const nm = mask | s;
                const val = base + cost;
                if (val < ndp[nm]) ndp[nm] = val;
            }
        }
        dp = ndp;
    }
    return dp[full];
};
